#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

typedef class_T bench_t;

static inline bench_t bench_element(bench_t x,
                                    bench_t f0,
                                    bench_t f1,
                                    bench_t f2,
                                    bench_t f3,
                                    bench_t f4,
                                    bench_t f5,
                                    bench_t f6,
                                    bench_t f7) {
  bench_t t0 = x;
  bench_t t1 = x;
  bench_t t2 = x;
  bench_t t3 = x;
  bench_t t4 = x;
  bench_t t5 = x;
  bench_t t6 = x;
  bench_t t7 = x;

  for (int j = 0; j < (COMPUTE_ITERATIONS / 8); ++j) {
    t0 = t0 * t0 + f0;
    t1 = t1 * t1 + f1;
    t2 = t2 * t2 + f2;
    t3 = t3 * t3 + f3;
    t4 = t4 * t4 + f4;
    t5 = t5 * t5 + f5;
    t6 = t6 * t6 + f6;
    t7 = t7 * t7 + f7;
  }

#if (COMPUTE_ITERATIONS % 8) > 0
  t0 = t0 * t0 + f0;
#endif
#if (COMPUTE_ITERATIONS % 8) > 1
  t1 = t1 * t1 + f1;
#endif
#if (COMPUTE_ITERATIONS % 8) > 2
  t2 = t2 * t2 + f2;
#endif
#if (COMPUTE_ITERATIONS % 8) > 3
  t3 = t3 * t3 + f3;
#endif
#if (COMPUTE_ITERATIONS % 8) > 4
  t4 = t4 * t4 + f4;
#endif
#if (COMPUTE_ITERATIONS % 8) > 5
  t5 = t5 * t5 + f5;
#endif
#if (COMPUTE_ITERATIONS % 8) > 6
  t6 = t6 * t6 + f6;
#endif

  return ((((((t0 + t1) + t2) + t3) + t4) + t5) + t6) + t7;
}

__attribute__((reqd_work_group_size(blockdim, 1, 1))) __kernel void
benchmark_func(bench_t seed, __global bench_t* data) {
  const size_t gid = get_global_id(0);
  const size_t gsize = get_global_size(0);
  const size_t lid = get_local_id(0);

  (void)seed;

  const bench_t f0 = data[0];
  const bench_t f1 = data[1];
  const bench_t f2 = data[2];
  const bench_t f3 = data[3];
  const bench_t f4 = data[4];
  const bench_t f5 = data[5];
  const bench_t f6 = data[6];
  const bench_t f7 = data[7];

  for (uint fusion = 0; fusion < (uint)FUSION_DEGREE; ++fusion) {
    for (uint e = 0; e < (uint)ELEMENTS_PER_THREAD; ++e) {
      const size_t linear =
          (size_t)fusion * (size_t)ELEMENTS_PER_THREAD + (size_t)e;

#ifdef BLOCK_STRIDED
      const size_t idx = (size_t)get_group_id(0) *
                             ((size_t)blockdim * (size_t)ELEMENTS_PER_THREAD *
                              (size_t)FUSION_DEGREE) +
                         lid + linear * (size_t)blockdim;
#else
      const size_t idx = gid + linear * gsize;
#endif

      const bench_t x = data[idx];
      data[idx] = bench_element(x, f0, f1, f2, f3, f4, f5, f6, f7);
    }
  }
}
